import { cva, type VariantProps } from 'class-variance-authority';
import { useId } from 'react';
import { cn } from '@/lib/utils';

const orbitSizeMap = {
  sm: 24,
  md: 32,
  lg: 44,
  xl: 60,
};

const arcSizeMap = {
  sm: 14,
  md: 16,
  lg: 20,
  xl: 24,
};

export const spinnerVariants = cva('', {
  variants: {
    size: {
      sm: '',
      md: '',
      lg: '',
      xl: '',
    },
  },
  defaultVariants: { size: 'md' },
});

interface SpinnerProps extends VariantProps<typeof spinnerVariants> {
  /**
   * "orbit"  — dois pontos traçando o símbolo Umbler (crescente + curva interna).
   * "arc"    — arco giratório, ideal para uso inline em botões.
   */
  variant?: 'orbit' | 'arc';
  /** Cor do ponto A (azul). Qualquer valor CSS. Padrão: #8BBCF8 */
  colorA?: string;
  /** Cor do ponto B (salmão). Qualquer valor CSS. Padrão: #F8C4B8 */
  colorB?: string;
  className?: string;
}

interface OrbitProps {
  px: number;
  colorA?: string;
  colorB?: string;
}

/**
 * Replica o loader oficial Umbler — dois pontos percorrem paths que
 * desenham o próprio símbolo da marca:
 *  - Ponto A (azul) percorre a CRESCENTE externa (C-shape).
 *  - Ponto B (salmão) percorre a CURVA interna (smile/u).
 *
 * Cada path é fechado, garantindo loop perfeito do animateMotion.
 * As durações diferentes criam o efeito de "perseguição" assimétrico
 * característico do GIF original (umbler-loader.gif).
 */
function OrbitDots({ px, colorA = '#8BBCF8', colorB = '#F8C4B8' }: OrbitProps) {
  // IDs únicos por instância evitam colisão quando múltiplos spinners renderizam
  // na mesma página.
  const uid = useId().replace(/:/g, '');
  const pathCrescent = `u-spin-crescent-${uid}`;
  const pathSmile = `u-spin-smile-${uid}`;

  return (
    <svg
      width={px}
      height={px}
      viewBox="0 0 48 48"
      fill="none"
      aria-hidden
      style={{ display: 'inline-block', flexShrink: 0, overflow: 'visible' }}
    >
      <defs>
        {/*
         * CRESCENTE (lua) — C-shape fechado.
         * - Outer arc: r=17 ao redor do centro (24,24), sweep horário ~270°
         * - Inner arc: r=10 retornando counter-clockwise
         * - Pequenos arcos de 3 unidades fazem as quinas no topo arredondadas,
         *   evitando saltos visíveis quando o dot transita entre as duas arcs.
         */}
        <path
          id={pathCrescent}
          d="
            M 36 12
            A 17 17 0 1 1 12 12
            A 3 3 0 0 0 18 16
            A 10 10 0 1 0 30 16
            A 3 3 0 0 0 36 12
            Z
          "
        />
        {/*
         * SMILE — pequena curva fechada (lente), centralizada abaixo do meio,
         * remetendo ao "u" interno do símbolo.
         */}
        <path
          id={pathSmile}
          d="
            M 31 27
            A 9 9 0 0 1 17 27
            A 9 9 0 0 1 31 27
            Z
          "
        />
      </defs>

      {/* Ponto A — azul, traça a crescente, mais lento (mais distância) */}
      <circle r={3} fill={colorA}>
        <animateMotion dur="1500ms" repeatCount="indefinite" rotate="0">
          <mpath href={`#${pathCrescent}`} />
        </animateMotion>
      </circle>

      {/* Ponto B — salmão, traça a curva interna, mais rápido — efeito de "perseguição" */}
      <circle r={2.2} fill={colorB}>
        <animateMotion dur="900ms" repeatCount="indefinite" rotate="0">
          <mpath href={`#${pathSmile}`} />
        </animateMotion>
      </circle>
    </svg>
  );
}

export function Spinner({ size = 'md', variant = 'orbit', colorA, colorB, className }: SpinnerProps) {
  if (variant === 'arc') {
    const px = arcSizeMap[size ?? 'md'];
    return (
      <svg
        width={px}
        height={px}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={2.5}
        strokeLinecap="round"
        className={cn('animate-spin', className)}
        aria-hidden
      >
        <path d="M21 12a9 9 0 1 1-6.219-8.56" />
      </svg>
    );
  }

  const px = orbitSizeMap[size ?? 'md'];
  return (
    <span className={cn('inline-flex items-center justify-center', className)}>
      <OrbitDots px={px} colorA={colorA} colorB={colorB} />
    </span>
  );
}
